// Benchmark boilerplate generated by Benchmark

import Benchmark
import Foundation

import Ifrit
import Fuse
import FuzzySearch

struct Person {
    let firstName: String
    let lastName: String
}

extension Person: Ifrit::Searchable {
    var props: [Ifrit::FuseProp] {
        [
            Ifrit::FuseProp(firstName),
            Ifrit::FuseProp(lastName),
        ]
    }
}

extension Person: FuzzySearch::Searchable {
    var searchDescriptor: FuzzySearch::SearchDescriptor {
        FuzzySearch::SearchDescriptor()
            .add(firstName)
            .add(lastName)
    }
}

let benchmarks: @Sendable () -> Void = {
    let people: [Person] = [
        Person(firstName: "John", lastName: "Doe"),
        Person(firstName: "Jane", lastName: "Smith"),
        Person(firstName: "Alice", lastName: "Johnson"),
        Person(firstName: "Bob", lastName: "Brown"),
        Person(firstName: "Charlie", lastName: "Davis"),
        Person(firstName: "Eve", lastName: "Miller"),
        Person(firstName: "Frank", lastName: "Wilson"),
        Person(firstName: "Grace", lastName: "Taylor"),
        Person(firstName: "Hank", lastName: "Anderson"),
        Person(firstName: "Ivy", lastName: "Thomas"),
        Person(firstName: "Thomas", lastName: "Shelby"),
        Person(firstName: "Arthur", lastName: "Shelby"),
        Person(firstName: "Polly", lastName: "Gray"),
        Person(firstName: "Michael", lastName: "Gray"),
    ]
    
    Benchmark("Ifrit") { benchmark in
        let fuse = Ifrit::Fuse()
        for _ in benchmark.scaledIterations {
            let results = await fuse.search("Tom Shelby", in: people, by: \.props)
            blackHole(results)
        }
    }
    
    Benchmark("Fuse") { benchmark in
        let options = try Fuse::FuseOptions<Person>(
            includeMatches: true,
            includeScore: true,
            keys: [
                try Fuse::FuseKey<Person>("firstName", keyPath: \Person.firstName),
                try Fuse::FuseKey<Person>("lastName", keyPath: \Person.lastName),
            ]
        )
        let fuse = try Fuse::Fuse.Search<Person>(people, options: options)
        for _ in benchmark.scaledIterations {
            let results = fuse.search("Tom Shelby")
            blackHole(results)
        }
    }
    
    Benchmark("Fuzzy") { benchmark in
        let fuzzy = FuzzySearch::Fuzzy()
        for _ in benchmark.scaledIterations {
            let results = await fuzzy.search(for: "Tom Shelby", in: people)
            blackHole(results)
        }
    }
}
